#include <stdio.h>
#include <stdlib.h>
#include <time.h>

void log_error(FILE* logfile, const char* error_msg) {
    time_t now;
    time(&now);
    
    fprintf(logfile, "[%s] ERROR: %s\n", ctime(&now), error_msg);
}

void log_detailed_error(FILE* logfile, const char* function_name, int line_number, const char* error_msg) {
    time_t now;
    time(&now);
    
    fprintf(logfile, "[%s] FUNCTION: %s, LINE: %d, ERROR: %s\n", 
            ctime(&now), function_name, line_number, error_msg);
}

void log_user_error(FILE* logfile, const char* user_input, const char* error_msg) {
    time_t now;
    time(&now);
    
    fprintf(logfile, "[%s] USER_INPUT: %s, ERROR: %s\n", 
            ctime(&now), user_input, error_msg);
}